/**
 * Disengages the auto-pilot and resets all configuration parameters to their defaults.
 * Also resets the target pitch, heading and roll, and clears all internal controller
 * state, including the oscillation detector's structural level — which otherwise
 * persists across engagements so that a craft known to be flexible re-latches quickly.
 */
static inline krpc_error_t krpc_SpaceCenter_AutoPilot_Reset(krpc_connection_t connection, krpc_SpaceCenter_AutoPilot_t instance);

/**
 * Set the target attitude from a nose direction and an up vector: point the nose along
 * direction and roll so the vessel's dorsal (roof) axis aligns with
 * up (its component perpendicular to the nose), then apply an optional
 * roll offset about the nose. Both vectors are in the reference frame
 * specified by SpaceCenter::AutoPilot::reference_frame.
 * @param direction The direction to point the nose in.
 * @param up The reference direction the roof is rolled towards. Need not be
 * normalized or perpendicular to direction — its component perpendicular
 * to the nose is used. Stored as the SpaceCenter::AutoPilot::up_reference.
 * @param roll An additional roll about the nose, in degrees (positive banks right).
 * Defaults to 0.
 *
 * This is the way to hold a well-defined orientation through a maneuver — for example a
 * gravity turn: pass a fixed up (say north) and the roll stays defined the
 * whole way, with no singularity at the vertical. It is well-defined for every nose direction
 * except up parallel to direction (asking the roof to
 * point where the nose already points), where it falls back to pointing the nose only.
 * Equivalent to setting SpaceCenter::AutoPilot::up_reference to up, aiming at
 * direction and setting SpaceCenter::AutoPilot::target_roll to
 * roll.
 */
static inline krpc_error_t krpc_SpaceCenter_AutoPilot_SetDirectionAndUp(krpc_connection_t connection, krpc_SpaceCenter_AutoPilot_t instance, const krpc_tuple_double_double_double_t * direction, const krpc_tuple_double_double_double_t * up, float roll);

/**
 * Set target pitch and heading angles.
 * @param pitch Target pitch angle, in degrees between -90° and +90°.
 * @param heading Target heading angle, in degrees between 0° and 360°.
 *
 * A convenience for aiming the nose by angle; heading is ill-defined when the nose is near
 * vertical (pitch → ±90°), so near the vertical prefer SpaceCenter::AutoPilot::target_direction or
 * SpaceCenter::AutoPilot::set_direction_and_up. Preserves the current roll relative to
 * SpaceCenter::AutoPilot::up_reference.
 */
static inline krpc_error_t krpc_SpaceCenter_AutoPilot_TargetPitchAndHeading(krpc_connection_t connection, krpc_SpaceCenter_AutoPilot_t instance, float pitch, float heading);

/**
 * Blocks until the vessel is pointing in the target direction and has
 * the target roll (if set). Throws an exception if the auto-pilot has not been engaged.
 * @param timeout Maximum time to wait in seconds. If not specified, waits indefinitely.
 */
static inline krpc_error_t krpc_SpaceCenter_AutoPilot_Wait(krpc_connection_t connection, krpc_SpaceCenter_AutoPilot_t instance, double timeout);

/**
 * The per-axis attitude error (pitch, yaw, roll), in degrees, between the vessel's current
 * attitude and the commanded target. All three components come from one singularity-free
 * residual decomposition, so they stay well-defined near the vertical (unlike a subtraction
 * of pitch/heading/roll angles). The scalar SpaceCenter::AutoPilot::pitch_error,
 * SpaceCenter::AutoPilot::heading_error and SpaceCenter::AutoPilot::roll_error are the magnitudes of the pitch, yaw
 * and roll components respectively. Throws an exception if the auto-pilot has not been
 * engaged.
 */
static inline krpc_error_t krpc_SpaceCenter_AutoPilot_AttitudeError(krpc_connection_t connection, krpc_tuple_double_double_double_t * returnValue, krpc_SpaceCenter_AutoPilot_t instance);

/**
 * Whether the rotation rate controllers PID parameters should be automatically tuned
 * using the vessels moment of inertia and available torque. Defaults to true.
 * See SpaceCenter::AutoPilot::time_to_peak and SpaceCenter::AutoPilot::overshoot.
 */
static inline krpc_error_t krpc_SpaceCenter_AutoPilot_AutoTune(krpc_connection_t connection, bool * returnValue, krpc_SpaceCenter_AutoPilot_t instance);

/**
 * Whether the rotation rate controllers PID parameters should be automatically tuned
 * using the vessels moment of inertia and available torque. Defaults to true.
 * See SpaceCenter::AutoPilot::time_to_peak and SpaceCenter::AutoPilot::overshoot.
 */
static inline krpc_error_t krpc_SpaceCenter_AutoPilot_set_AutoTune(krpc_connection_t connection, krpc_SpaceCenter_AutoPilot_t instance, bool value);

/**
 * The per-axis attitude error (pitch, yaw, roll), in degrees, between the vessel's current
 * attitude and the target the auto-pilot is currently tracking (the slewed target — see
 * SpaceCenter::AutoPilot::current_target_rotation). Like SpaceCenter::AutoPilot::attitude_error but relative to the
 * current target, so it stays small while a smoothed change (see
 * SpaceCenter::AutoPilot::target_smoothing_time) is fed in; equal to SpaceCenter::AutoPilot::attitude_error when
 * smoothing is off. Throws an exception if the auto-pilot has not been engaged.
 */
static inline krpc_error_t krpc_SpaceCenter_AutoPilot_CurrentAttitudeError(krpc_connection_t connection, krpc_tuple_double_double_double_t * returnValue, krpc_SpaceCenter_AutoPilot_t instance);

/**
 * The error, in degrees, between the direction the auto-pilot is currently tracking and the
 * direction the ship is pointing in. Unlike SpaceCenter::AutoPilot::error (which is relative to the
 * commanded target), this is relative to the slewed target the auto-pilot is currently
 * holding, so it stays small while a smoothed change (see SpaceCenter::AutoPilot::target_smoothing_time)
 * is fed in. Equal to SpaceCenter::AutoPilot::error when smoothing is off. Throws an exception if the
 * auto-pilot has not been engaged.
 */
static inline krpc_error_t krpc_SpaceCenter_AutoPilot_CurrentError(krpc_connection_t connection, float * returnValue, krpc_SpaceCenter_AutoPilot_t instance);

/**
 * The error, in degrees, between the vessels current heading and the heading the auto-pilot
 * is currently tracking (see SpaceCenter::AutoPilot::current_target_heading). Throws an exception if the
 * auto-pilot has not been engaged.
 *
 * The yaw component of SpaceCenter::AutoPilot::current_attitude_error, well-defined near the vertical.
 */
static inline krpc_error_t krpc_SpaceCenter_AutoPilot_CurrentHeadingError(krpc_connection_t connection, float * returnValue, krpc_SpaceCenter_AutoPilot_t instance);

/**
 * The error, in degrees, between the vessels current pitch and the pitch the auto-pilot is
 * currently tracking (see SpaceCenter::AutoPilot::current_target_pitch). Throws an exception if the
 * auto-pilot has not been engaged.
 *
 * The pitch component of SpaceCenter::AutoPilot::current_attitude_error, well-defined near the vertical.
 */
static inline krpc_error_t krpc_SpaceCenter_AutoPilot_CurrentPitchError(krpc_connection_t connection, float * returnValue, krpc_SpaceCenter_AutoPilot_t instance);

/**
 * The error, in degrees, between the vessels current roll and the roll the auto-pilot is
 * currently tracking (see SpaceCenter::AutoPilot::current_target_roll). Throws an exception if the
 * auto-pilot has not been engaged or no target roll is set.
 *
 * Measured about the vessel's nose axis, so it stays well-defined near the vertical
 * singularity — see SpaceCenter::AutoPilot::roll_error.
 */
