/**
 * Simulate and return the total aerodynamic forces acting on the vessel,
 * if it were traveling with the given velocity, at the given position and
 * orientation, in the atmosphere of the given celestial body.
 * @param body The celestial body whose atmosphere the forces are simulated in.
 * @param position The position of the vessel, in reference frame
 * SpaceCenter::ReferenceFrame.
 * @param velocity The velocity of the vessel, in reference frame
 * SpaceCenter::ReferenceFrame.
 * @param rotation The orientation of the vessel, in reference frame
 * SpaceCenter::ReferenceFrame, in the same form as SpaceCenter::Vessel::rotation.
 * The angle of attack and sideslip follow from this orientation relative to the
 * velocity; the roll component sets the direction of any aerodynamic lift. Pass
 * the vessel's current rotation to evaluate the force at its current orientation.
 * @return A vector pointing in the direction that the force acts, with its
 * magnitude equal to the strength of the force in Newtons, in reference frame
 * SpaceCenter::ReferenceFrame.
 *
 * The position, velocity and rotation arguments, and the returned force, are all
 * expressed in reference frame SpaceCenter::ReferenceFrame. The result is the
 * force the vessel would experience if it were placed at that position and
 * orientation with the air flowing past it at that velocity; it is the force at
 * the requested orientation, not the force in the vessel's current orientation.
 * Atmospheric temperature and density are evaluated at the current universal time.
 */
static inline krpc_error_t krpc_SpaceCenter_Flight_SimulateAerodynamicForceAt(krpc_connection_t connection, krpc_tuple_double_double_double_t * returnValue, krpc_SpaceCenter_Flight_t instance, krpc_SpaceCenter_CelestialBody_t body, const krpc_tuple_double_double_double_t * position, const krpc_tuple_double_double_double_t * velocity, const krpc_tuple_double_double_double_double_t * rotation);

/**
 * Simulate and return the total aerodynamic torque acting on the vessel about its
 * center of mass, if it were traveling with the given velocity, at the given
 * position, orientation and angular velocity, in the atmosphere of the given
 * celestial body.
 * @param body The celestial body whose atmosphere the torque is simulated in.
 * @param position The position of the vessel, in reference frame
 * SpaceCenter::ReferenceFrame.
 * @param velocity The velocity of the vessel, in reference frame
 * SpaceCenter::ReferenceFrame.
 * @param rotation The orientation of the vessel, in reference frame
 * SpaceCenter::ReferenceFrame, in the same form as SpaceCenter::Vessel::rotation.
 * Pass the vessel's current rotation to evaluate the torque at its current
 * orientation.
 * @param angularVelocity The angular velocity of the vessel, in reference
 * frame SpaceCenter::ReferenceFrame. This adds the solid-body rotation term to each
 * part's local airflow and the per-part rigid-body angular drag the game applies,
 * together giving the aerodynamic damping torque. Pass a zero vector to
 * evaluate the static torque.
 * @return A vector pointing along the axis of the torque, with its magnitude equal
 * to the strength of the torque in newton-meters, in reference frame
 * SpaceCenter::ReferenceFrame.
 *
 * The position, velocity, rotation and angular velocity arguments, and the returned
 * torque, are all expressed in reference frame SpaceCenter::ReferenceFrame. When
 * <a href="https://forum.kerbalspaceprogram.com/index.php?/topic/19321-130-ferram-aerospace-research-v0159-liebe-82117/">Ferram Aerospace Research</a>
 * is installed the angular velocity argument is ignored.
 * Atmospheric temperature and density are evaluated at the current universal time.
 *
 * This is the ideal rigid-body aerodynamic torque, summed from the per-part forces
 * about the center of mass. A vessel may not visibly rotate by the full amount when
 * a large aerodynamic force acts on a small part far from the center of mass, because
 * the game applies each part's force to that part and propagates it through the joints
 * rather than to the vessel as a rigid body.
 */
static inline krpc_error_t krpc_SpaceCenter_Flight_SimulateAerodynamicTorqueAt(krpc_connection_t connection, krpc_tuple_double_double_double_t * returnValue, krpc_SpaceCenter_Flight_t instance, krpc_SpaceCenter_CelestialBody_t body, const krpc_tuple_double_double_double_t * position, const krpc_tuple_double_double_double_t * velocity, const krpc_tuple_double_double_double_double_t * rotation, const krpc_tuple_double_double_double_t * angularVelocity);

/**
 * Simulate and return the total aerodynamic force and torque acting on the vessel,
 * if its center of mass were traveling with the given velocity, at the given position,
 * orientation and angular velocity, in the atmosphere of the given celestial body.
 * @param body The celestial body whose atmosphere the wrench is simulated in.
 * @param position The position of the vessel's center of mass, in reference
 * frame SpaceCenter::ReferenceFrame.
 * @param velocity The velocity of the vessel's center of mass, in reference
 * frame SpaceCenter::ReferenceFrame.
 * @param rotation The orientation of the vessel, in reference frame
 * SpaceCenter::ReferenceFrame, in the same form as SpaceCenter::Vessel::rotation.
 * Pass the vessel's current rotation to evaluate the wrench at its current
 * orientation.
 * @param angularVelocity The angular velocity of the vessel, in reference
 * frame SpaceCenter::ReferenceFrame. This adds the solid-body rotation term to each
 * part's local airflow and the per-part rigid-body angular drag the game applies,
 * together giving the aerodynamic damping force and torque. Pass a zero vector to
 * evaluate the static wrench relative to the reference frame.
 * @param ut The universal time used for the atmospheric ephemeris. It
 * selects the body/Sun geometry used for temperature and density, but does not
 * change or propagate SpaceCenter::ReferenceFrame or any of the state arguments.
 * @return A pair containing the aerodynamic force in newtons followed by the
 * aerodynamic torque in newton-meters about the vessel's center of mass. Both are
 * vectors in reference frame SpaceCenter::ReferenceFrame.
 *
 * The position and velocity describe the hypothetical center-of-mass state. The
 * position, velocity, rotation and angular velocity arguments, and both returned
 * vectors, are expressed in reference frame SpaceCenter::ReferenceFrame.
 * For future-state prediction, SpaceCenter::CelestialBody::non_rotating_reference_frame
 * is recommended so that the spatial state has unambiguous inertial semantics.
 *
 * This is an instantaneous rigid-body result based on the vessel's current parts,
 * drag cubes and control-surface state. When
 * <a href="https://forum.kerbalspaceprogram.com/index.php?/topic/19321-130-ferram-aerospace-research-v0159-liebe-82117/">Ferram Aerospace Research</a>
 * is installed the angular velocity and ut arguments are ignored.
 */
static inline krpc_error_t krpc_SpaceCenter_Flight_SimulateAerodynamicWrenchAt(krpc_connection_t connection, krpc_tuple_tuple_double_double_double_tuple_double_double_double_t * returnValue, krpc_SpaceCenter_Flight_t instance, krpc_SpaceCenter_CelestialBody_t body, const krpc_tuple_double_double_double_t * position, const krpc_tuple_double_double_double_t * velocity, const krpc_tuple_double_double_double_double_t * rotation, const krpc_tuple_double_double_double_t * angularVelocity, double ut);

/**
 * The acceleration of the vessel, in the reference frame SpaceCenter::ReferenceFrame.
 * This is the total acceleration, including the acceleration due to gravity, and is the
 * time derivative of SpaceCenter::Flight::velocity.
 * @return The acceleration as a vector. The vector points in the direction of the
 * acceleration, and its magnitude is the acceleration of the vessel in m/s^2.
 */
static inline krpc_error_t krpc_SpaceCenter_Flight_Acceleration(krpc_connection_t connection, krpc_tuple_double_double_double_t * returnValue, krpc_SpaceCenter_Flight_t instance);

/**
 * The acceleration of the vessel due to the total aerodynamic forces acting on it
 * (SpaceCenter::Flight::aerodynamic_force divided by the vessel's mass),
 * in reference frame SpaceCenter::ReferenceFrame.
 * @return A vector pointing in the direction that the vessel is accelerated,
 * with its magnitude equal to the acceleration in m/s^2.
 */
static inline krpc_error_t krpc_SpaceCenter_Flight_AerodynamicAcceleration(krpc_connection_t connection, krpc_tuple_double_double_double_t * returnValue, krpc_SpaceCenter_Flight_t instance);

/**
 * The total aerodynamic forces acting on the vessel,
 * in reference frame SpaceCenter::ReferenceFrame.
 * @return A vector pointing in the direction that the force acts,
 * with its magnitude equal to the strength of the force in Newtons.
 */
static inline krpc_error_t krpc_SpaceCenter_Flight_AerodynamicForce(krpc_connection_t connection, krpc_tuple_double_double_double_t * returnValue, krpc_SpaceCenter_Flight_t instance);

/**
 * The net aerodynamic torque currently acting on the vessel about its center of
 * mass, in reference frame SpaceCenter::ReferenceFrame. The magnitude is in
 * newton-meters.
 * @return A vector pointing along the axis of the torque, with its magnitude
 * equal to the strength of the torque in newton-meters.
 *
 * This is the live counterpart to SpaceCenter::Flight::aerodynamic_force: it reconstructs
 * the per-part aerodynamic forces and application points that the game applied on
 * the current physics frame and levers them about the center of mass, rather than
 * re-simulating them for hypothetical conditions the way
 * SpaceCenter::Flight::simulate_aerodynamic_torque_at does. It is intended for validating the
 * simulator against the live game state. Not available when
 * <a href="https://forum.kerbalspaceprogram.com/index.php?/topic/19321-130-ferram-aerospace-research-v0159-liebe-82117/">Ferram Aerospace Research</a>
 * is installed, as FAR does not expose a live per-frame torque.
 */
static inline krpc_error_t krpc_SpaceCenter_Flight_AerodynamicTorque(krpc_connection_t connection, krpc_tuple_double_double_double_t * returnValue, krpc_SpaceCenter_Flight_t instance);

